mapper.select:


    e.del_flag = '0'
    and e.task_id = #{taskId}
    and t.task_no like concat('%', #{taskNo}, '%')
    and e.sop_instance_uid like concat('%', #{sopInstanceUid}, '%')
    and e.defect_type like concat('%', #{defectType}, '%')
    and e.defect_level = #{defectLevel}
    and e.status = #{status}

        and exists (
            select 1 from ndt_task_user tu
             where tu.task_id = e.task_id and tu.user_id = #{params.scopeUserId} and tu.can_view = '1'
        )

    and t.customer_dept_id = #{params.scopeDeptId}
    and 1 = 0

order by e.evaluate_time desc, e.id desc

